import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import Counter from './Counter';

test('incrementa ao clicar', async () => {
  render(<Counter />);
  await userEvent.click(screen.getByRole('button', { name: /incrementar/i }));
  expect(screen.getByText(/1/)).toBeInTheDocument();
});

import { render, screen } from '@testing-library/react';
import Alert from './Alert';

test('exibe mensagem de erro quando type é error', () => {
  render(<Alert type="error" message="Algo deu errado" />);
  expect(screen.getByRole('alert')).toHaveTextContent('Algo deu errado');
});

test('não renderiza quando message é vazia', () => {
  const { container } = render(<Alert type="info" message="" />);
  expect(container).toBeEmptyDOMElement();
});
